import React, { useEffect, useState, useMemo } from 'https://esm.sh/react@18.2.0';
import ReactDOM from 'https://esm.sh/react-dom@18.2.0/client';

function IZODonutChart(props) {
  const [isLoaded, setIsLoaded] = useState(false);
  const [tooltip, setTooltip] = useState({ show: false, x: 0, y: 0, name: '', count: 0 });

  useEffect(() => {
    const styleId = 'izo-nba-final-styles';
    if (!document.getElementById(styleId)) {
      const style = document.createElement('style');
      style.id = styleId;
      style.innerHTML = `
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap');
        html, body, #root { 
          height: 100% !important; 
          margin: 0; padding: 0; 
          overflow: hidden !important; 
          font-family: 'Inter', sans-serif; 
          background: white;
        }
        .legend-scroll::-webkit-scrollbar { width: 4px; }
        .legend-scroll::-webkit-scrollbar-track { background: transparent; }
        .legend-scroll::-webkit-scrollbar-thumb { background: #E2E8F0; border-radius: 10px; }

        .izo-tooltip {
          position: fixed;
          pointer-events: none;
          background: #1f2937;
          color: white;
          padding: 8px 12px;
          border-radius: 6px;
          font-size: 12px;
          z-index: 9999;
          box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1);
          transform: translate(-50%, -120%);
          transition: opacity 0.1s ease;
          white-space: nowrap;
        }
      `;
      document.head.appendChild(style);
    }

    if (!document.getElementById('tailwind-v4')) {
      const script = document.createElement('script');
      script.id = 'tailwind-v4';
      script.src = 'https://cdn.jsdelivr.net/npm/@tailwindcss/browser@4';
      script.onload = () => setIsLoaded(true);
      document.head.appendChild(script);
    } else {
      setIsLoaded(true);
    }
  }, []);

  const resolved = useMemo(() => {
    const raw = props.data || {};
    const list = raw.data || [
      { name: "Active", count: 231 },
      { name: "Accepted", count: 170 },
      { name: "Dismissed", count: 56 },
      { name: "Defer", count: 68 }
    ];

    const defaultColors = ["#004B7D", "#93C1D9", "#A6CBE1", "#D9EBF5"];
    const colors = (raw.colors && Array.isArray(raw.colors)) ? raw.colors : defaultColors;
    const total = raw.total || list.reduce((a, b) => a + b.count, 0);

    const dataSum = list.reduce((a, b) => a + b.count, 0);
    let cumulativePercent = 0;
    const segments = list.map((item, index) => {
      const slicePercent = dataSum > 0 ? item.count / dataSum : 0;
      const startX = Math.cos(2 * Math.PI * cumulativePercent);
      const startY = Math.sin(2 * Math.PI * cumulativePercent);
      cumulativePercent += slicePercent;
      const endX = Math.cos(2 * Math.PI * cumulativePercent);
      const endY = Math.sin(2 * Math.PI * cumulativePercent);

      const largeArcFlag = slicePercent > 0.5 ? 1 : 0;
      const pathData = [
        `M ${startX} ${startY}`, 
        `A 1 1 0 ${largeArcFlag} 1 ${endX} ${endY}`,
        `L 0 0`
      ].join(' ');

      return { ...item, path: pathData, color: colors[index % colors.length] };
    });

    return {
      title: raw.title || "NBA Status",
      subtitle: raw.subtitle || "Overview of accepted, deferred, and dismissed recommendations.",
      total,
      segments
    };
  }, [props.data]);

  const handleShowTooltip = (e, item) => {
    setTooltip({
      show: true,
      x: e.clientX,
      y: e.clientY,
      name: item.name,
      count: item.count
    });
  };

  const handleHideTooltip = () => setTooltip(prev => ({ ...prev, show: false }));

  if (!isLoaded) return null;

  const { title, subtitle, total, segments } = resolved;

  return React.createElement(
    'div',
    { className: "flex flex-col h-full w-full p-8 bg-white overflow-hidden" },

    // Shared Tooltip
    tooltip.show && React.createElement(
      'div',
      { 
        className: "izo-tooltip",
        style: { left: tooltip.x, top: tooltip.y }
      },
      React.createElement('div', { className: "font-semibold" }, tooltip.name),
      React.createElement('div', { className: "opacity-80 text-[11px] mt-0.5" }, `Count: ${tooltip.count}`)
    ),

    // Header
    React.createElement(
      'div',
      { className: "mb-6 shrink-0" },
      React.createElement('h3', { className: "text-[16px] font-medium text-[#252726] mb-1" }, title),
      React.createElement('p', { className: "text-[14px] font-regular text-[#252726] opacity-80" }, subtitle)
    ),

    // Content Layout
    React.createElement(
      'div',
      { className: "flex items-start gap-10 flex-1 min-h-0 overflow-hidden pt-2" },

      // Donut Visual
      React.createElement(
        'div',
        { className: "relative w-[160px] h-[160px] shrink-0" },
        React.createElement(
          'svg',
          { viewBox: "-1 -1 2 2", className: "w-full h-full -rotate-90" },
          segments.map((seg, i) => React.createElement('path', {
            key: i,
            d: seg.path,
            fill: seg.color,
            className: "transition-opacity hover:opacity-90 cursor-pointer",
            onMouseEnter: (e) => handleShowTooltip(e, seg),
            onMouseMove: (e) => handleShowTooltip(e, seg),
            onMouseLeave: handleHideTooltip,
            onClick: () => props.updateData({ selected: seg.name })
          })),
          React.createElement('circle', { r: "0.75", fill: "white" })
        ),
        React.createElement(
          'div',
          { className: "absolute inset-0 flex flex-col items-center justify-center pointer-events-none text-center" },
          React.createElement('span', { className: "text-[10px] font-semibold text-[#7C858C] tracking-wide" }, "Total NBAs"),
          React.createElement('span', { className: "text-[24px] font-semibold text-[#7C858C] leading-none mt-1" }, total)
        )
      ),

      // Legend Section
      React.createElement(
        'div',
        { className: "legend-scroll flex flex-col gap-4 overflow-y-auto pr-2 flex-1 h-full min-h-0" },
        segments.map((item, index) => React.createElement(
          'div',
          { 
            key: index, 
            className: "flex items-center group cursor-pointer shrink-0",
            onClick: () => props.updateData({ selected: item.name }),
            onMouseEnter: (e) => handleShowTooltip(e, item),
            onMouseMove: (e) => handleShowTooltip(e, item),
            onMouseLeave: handleHideTooltip
          },

          // Name Column
          React.createElement(
            'div',
            { className: "flex items-center gap-2.5 w-40 shrink-0 min-w-0" },
            React.createElement('span', { 
              className: "w-2.5 h-2.5 rounded-full shrink-0", 
              style: { backgroundColor: item.color } 
            }),
            React.createElement('span', { 
              className: "text-[14px] font-medium text-[#7C858C] truncate group-hover:text-[#252726]"
            }, item.name)
          ),

          // Count Column
          React.createElement(
            'span', 
            { className: "text-[14px] font-semibold text-[#7C858C] w-12 tabular-nums ml-4 shrink-0" }, 
            item.count
          )
        ))
      )
    )
  );
}

const ConnectedComponent = Tooljet.connectComponent(IZODonutChart);
if (!window.tooljetRoot) {
  window.tooljetRoot = ReactDOM.createRoot(document.body);
}
window.tooljetRoot.render(React.createElement(ConnectedComponent));
